// Validate that the incoming payload has minimum required fields.
// This workflow only processes data from pre-approved, authorised sources.
const items = $input.all();
const valid = [];
const invalid = [];
for (const item of items) {
  const p = item.json;
  if (!p.firstName && !p.first_name && !p.name) {
    invalid.push({ ...item.json, _validationError: 'Missing name fields' });
    continue;
  }
  valid.push(item);
}
if (invalid.length > 0) {
  console.warn(`Skipped ${invalid.length} records with missing required fields`);
}
return valid;

const items = $input.all();
return items.map(item => {
  const p = item.json;
  // Normalise field names from various source formats
  const firstName = p.firstName ?? p.first_name ?? (p.name ?? '').split(' ')[0] ?? '';
  const lastName = p.lastName ?? p.last_name ?? (p.name ?? '').split(' ').slice(1).join(' ') ?? '';
  return {
    json: {
      firstName,
      lastName,
      email: p.email ?? p.emailAddress ?? null,
      phone: p.phone ?? p.mobile ?? p.phoneNumber ?? null,
      currentTitle: p.title ?? p.currentTitle ?? p.jobTitle ?? null,
      currentCompany: p.company ?? p.currentCompany ?? p.employer ?? null,
      skills: Array.isArray(p.skills) ? p.skills : (p.skills ? [p.skills] : []),
      source: p._source ?? 'WEBHOOK',
      sourceRef: p._sourceRef ?? null,
      rawData: p
    }
  };
});
